const crypto = require('crypto');
const ACCESS_KEY = 'admin';
const SECRET_KEY = 'Admin1234!';
const HOST = 'host.docker.internal:25000';
const REGION = 'us-east-1';

function sigv4(method, path, body) {
  const now = new Date();
  const p = n => String(n).padStart(2, '0');
  const amzDate = `${now.getUTCFullYear()}${p(now.getUTCMonth()+1)}${p(now.getUTCDate())}T${p(now.getUTCHours())}${p(now.getUTCMinutes())}${p(now.getUTCSeconds())}Z`;
  const dateStamp = amzDate.slice(0,8);
  const payloadHash = crypto.createHash('sha256').update(body||'').digest('hex');
  const canonHeaders = `host:${HOST}\nx-amz-content-sha256:${payloadHash}\nx-amz-date:${amzDate}\n`;
  const signedHdrs = 'host;x-amz-content-sha256;x-amz-date';
  const canonReq = [method, path, '', canonHeaders, signedHdrs, payloadHash].join('\n');
  const credScope = `${dateStamp}/${REGION}/s3/aws4_request`;
  const strToSign = `AWS4-HMAC-SHA256\n${amzDate}\n${credScope}\n${crypto.createHash('sha256').update(canonReq).digest('hex')}`;
  const hmac = (k,d) => crypto.createHmac('sha256',k).update(d).digest();
  const kDate = hmac(Buffer.from('AWS4'+SECRET_KEY), dateStamp);
  const kReg  = hmac(kDate,  REGION);
  const kSvc  = hmac(kReg,   's3');
  const kSign = hmac(kSvc,   'aws4_request');
  const sig   = crypto.createHmac('sha256', kSign).update(strToSign).digest('hex');
  return {
    amz_date: amzDate,
    payload_hash: payloadHash,
    auth: `AWS4-HMAC-SHA256 Credential=${ACCESS_KEY}/${credScope}, SignedHeaders=${signedHdrs}, Signature=${sig}`
  };
}

const { amz_date, payload_hash, auth } = sigv4('PUT', '/screenshots', '');
return [{json: { url: `http://${HOST}/screenshots`, auth, amz_date, payload_hash }}];

