const item = $input.first();
const filename = `screenshot_${Date.now()}.png`;
const objectPath = `/${BUCKET}/${filename}`;
const buf = Buffer.from(item.binary.data.data, 'base64');
const payloadHash = crypto.createHash('sha256').update(buf).digest('hex');
const { amz_date, auth } = sigv4('PUT', objectPath, payloadHash);

return [{
  json: {
    minio_url: `http://${HOST}${objectPath}`,
    filename,
    bucket: BUCKET,
    auth,
    amz_date,
    payload_hash: payloadHash
  },
  binary: item.binary
}];
